targetCode.css:
body {
  margin: 0;
  min-height: 100vh;
  display: grid;
  place-items: center;
  background: #f7f3ea;
}

.escena {
  width: 360px;
  padding: 20px;
  border: 2px dashed #cbd5e1;
  overflow: auto;
}

#p1,
#p2 {
  width: 100px;
  height: 100px;
  border: 2px solid #111827;
}

#p1 {
  background: #d62828;
  float: left;
}

#p2 {
  background: #2563eb;
  float: right;
}
